<template>
  <div style="max-width:900px;margin:24px auto">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
      <el-tabs v-model="tab" style="flex:1">
        <el-tab-pane label="未读" name="unread" />
        <el-tab-pane label="已读" name="read" />
      </el-tabs>
      <div style="display:flex;gap:12px;align-items:center">
        <el-select v-model="type" placeholder="类型" style="width:160px" clearable>
          <el-option label="全部" value="" />
          <el-option label="系统" value="AUDIT" />
          <el-option label="匹配" value="MATCH" />
          <el-option label="认领" value="CLAIM" />
          <el-option label="公告" value="NOTICE" />
        </el-select>
        <el-button @click="markAllRead" type="primary" plain>全部已读</el-button>
      </div>
    </div>
    <el-table :data="list" style="width:100%">
      <el-table-column label="类型" width="120">
        <template #default="{row}">
          <el-tag size="small" :type="tagType(row.type)">{{ typeText(row.type) }}</el-tag>
        </template>
      </el-table-column>
      <el-table-column prop="title" label="标题" />
      <el-table-column prop="content" label="内容" />
      <el-table-column label="操作" width="200">
        <template #default="{row}">
          <el-button size="small" @click="read(row)" :disabled="tab==='read'">标记已读</el-button>
          <el-button size="small" type="danger" @click="remove(row)">删除</el-button>
        </template>
      </el-table-column>
    </el-table>
  </div>
  </template>
  <script setup lang="ts">
  import { ref, watch } from 'vue'
  import http from '../api/http'
  const tab = ref('unread')
  const type = ref<string | ''>('')
  const list = ref<any[]>([])
  function typeText(t:string) { return ({AUDIT:'系统', MATCH:'匹配', CLAIM:'认领', NOTICE:'公告'} as any)[t] || '其他' }
  function tagType(t:string) { return ({AUDIT:'info', MATCH:'warning', CLAIM:'success', NOTICE:'primary'} as any)[t] || 'default' }
  async function load() {
    const isRead = tab.value === 'read' ? true : false
    const { data } = await http.get('/message', { params: { page: 0, size: 100, type: type.value || undefined, isRead } })
    list.value = data.records || []
  }
  watch(tab, load, { immediate: true })
  watch(type, load)
  async function read(row:any) { await http.put(`/message/${row.id}/read`); load() }
  async function remove(row:any) { await http.delete(`/message/${row.id}`); load() }
  async function markAllRead() { await http.put('/message/read-all'); load() }
  </script>
